        if (sigma == 0) {
            for (int i = 0; i < N; i++) printf("0 ");
            printf("\n");
        } else if (N == 1) {
            printf("%lf\n", sigma);
        } else {
            double mean = 0;
            double sum = 0;
            for (int i = 0; i < N - 1; i++) {
                printf("0 ");
