        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            double sigma = sc.nextDouble();
            if (sigma == 0) {
                for (int i = 0; i < N; i++) System.out.print(0 + " ");
                System.out.println();
            } else if (N == 1) {
                System.out.println(sigma);
            } else {
                double mean = 0;
                double sum = 0;
                for (int i = 0; i < N - 1; i++) {
                    System.out.print(0 + " ");
                    sum += 0;
                }
                double last = Math.sqrt(N * sigma * sigma);
                System.out.println(last);
            }
        }
    }
}

